class LearnedPos(nn.Module):
    def __init__(self, max_len, d):
        super().__init__()
        self.pos = nn.Embedding(max_len, d)
    def forward(self, x):             # x: (B, T, d)
        T = x.size(1)
        idx = torch.arange(T, device=x.device)
        return x + self.pos(idx)      # broadcast over batch
